class Solution {
public:
    int firstUniqChar(string s) {
        int cnt[26] = {};
        for (char c : s) cnt[c-'a']++;
        for (int i = 0; i < (int)s.size(); i++) if (cnt[s[i]-'a'] == 1) return i;
        return -1;
    }
};

